// AI-generated sample headshots (not real people) used by the template
// picker sample resumes. Inlined as data URIs — not plain /public paths —
// so the dedicated PDF exporters (which only embed data:image/* photos,
// matching how real user uploads are stored via FileReader) can draw them
// into the exported PDF, not just the on-screen preview.

export const DANIEL_AVATAR = 'data:image/jpeg;base64,';

export const CAMILA_AVATAR = 'data:image/jpeg;base64,';
